<?phpnamespace App\Controller;use App\Entity\Authority;use App\Entity\KohUtilisateur;use App\Entity\Structure;use App\Entity\SysAdminOperation;use App\Form\EditKohClientType;use App\Form\KohClientType;use App\Form\StructureType;use App\Repository\AuthorityRepository;use App\Repository\BienClientRepository;use App\Repository\ExpertiseRepository;use App\Repository\KohUtilisateurRepository;use App\Repository\StructureRepository;use App\Repository\TypeCompteRepository;use DateTime;use DateTimeZone;use Doctrine\ORM\NonUniqueResultException;use Doctrine\ORM\NoResultException;use Exception;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Swift_Mailer;use Swift_Message;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\File\UploadedFile;use Symfony\Component\HttpFoundation\JsonResponse;use Symfony\Component\HttpFoundation\RedirectResponse;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;use Symfony\Component\Security\Core\Encoder\UserPasswordEncoderInterface;class GestionClientController extends AbstractController{    /**     * @var KohUtilisateurRepository     */    private $kohUtilisateurRepository;    public function __construct(KohUtilisateurRepository $kohUtilisateurRepository)    {        $this->kohUtilisateurRepository = $kohUtilisateurRepository;    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/clients", name="super_admin.clients")     */    public function index(): Response    {        return $this->render('koh_clients/index.html.twig', [            'clients' => $this->kohUtilisateurRepository->koh_clients()        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/clients/new", name="super_admin.clients.new")     * @param Request $request     * @param StructureRepository $structureRepository     * @param UserPasswordEncoderInterface $encoder     * @param Swift_Mailer $mailer     * @param AuthorityRepository $authorityRepository     * @return Response     * @throws Exception     */    public function new(Request $request, StructureRepository $structureRepository, UserPasswordEncoderInterface $encoder, Swift_Mailer $mailer, AuthorityRepository $authorityRepository): ?Response    {        $kohUtilisateur = new KohUtilisateur();        $form = $this->createForm(KohClientType::class, $kohUtilisateur);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $kohUtilisateur->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')));            $kohUtilisateur->setIsActived(false);            $kohUtilisateur->setIsAdmin(true);            $kohUtilisateur->setIsKohUser(false);            $kohUtilisateur->setUsername($kohUtilisateur->getEmail());            $kohUtilisateur->setStatus('profil non complete');            $kohUtilisateur->setTypeCompte($kohUtilisateur->getTypeCompte());            $kohUtilisateur->setStatus('Compte suspendu');            $date = new DateTime('now', new DateTimeZone('GMT'));            $time = $date->getTimestamp() + (24 * 60 * 60);            $kohUtilisateur->setTokenValidity($time);            $random = $this->generate_string(100);            $kohUtilisateur->setConfirmationToken($random);            $kohUtilisateur->setIsConfirmed(false);            $kohUtilisateur->setPassword($encoder->encodePassword($kohUtilisateur, $kohUtilisateur->getPassword()));            if ($kohUtilisateur->getTypeCompte()->getIsStructure()) {                if ($structureRepository->findOneBy(['name' => $request->get('nom_structure')]) !== null) {                    $this->addFlash('error', 'Cette structure a été déjà enregistré veuillez saisir une autre');                    return $this->render('koh_clients/new.html.twig', [                        'form' => $form->createView(),                        'koh_utilisateur' => $kohUtilisateur,                    ]);                }                $structure = new Structure();                $structure->setName($request->get('nom_structure'));                $structure->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')));                $structure->setAdresse($request->get('adresse_structure'));                $structure->setTelephone($request->get('tel_structure'));                // TODO REPLACE CODE                $file = $request->files->get('logo_structure');                if ($file) {                    // $fileF = new UploadedFile(                        // $file['tmp_name'],                        // $file['name']);                    // $structure->setStructureProfile($fileF);                    $structure->setStructureProfile($file);                }                // $structure->setStructureProfile($request->files->get('logo_structure'));                $entityManager->persist($structure);                $kohUtilisateur->setStructure($structure);                $kohUtilisateur->setNomStructure($structure->getName());                $kohUtilisateur->setStructure($structure);            }            $role = $authorityRepository->findOneBy(['name' => 'ADMIN']);            if ($role === null) {                $role = new Authority();                $role->setName('ADMIN')                    ->setDescription('Rôle admin des clients mbeyan')                    ->setIsRoleKoh(false);                $entityManager->persist($role);                $entityManager->flush();            }            $kohUtilisateur->addAuthority($role);            $entityManager->persist($kohUtilisateur);            $entityManager->flush();            $structure = $kohUtilisateur->getStructure();            $message = (new Swift_Message("création de compte"))                ->setFrom('contact@mbeyan.com')                ->setTo($kohUtilisateur->getEmail())                ->setBody($this->renderView(                    'mailer/registration.html.twig',                    [                        'firstName' => $kohUtilisateur->getFirstName(),                        'lastName' => $kohUtilisateur->getLastName(),                        'random' => $random,                        'structure' => $structure                    ]                ),                    'text/html');            $mailer->send($message);            $this->addFlash('success', "Le compte du client a été crée avec succès");            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Enregistrement compte client');            if ($kohUtilisateur->getTypeCompte()->getIsStructure()) {                $sysOp->setUserAffected($kohUtilisateur->getStructure()->getName());            } else {                $sysOp->setUserAffected($kohUtilisateur->getEmail());            }            $entityManager->persist($sysOp);            $entityManager->flush();            return $this->redirectToRoute('super_admin.clients');        }        return $this->render('koh_clients/new.html.twig', [            'form' => $form->createView(),            'koh_utilisateur' => $kohUtilisateur,        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/clients/structures", name="super_admin.structures")     * @param StructureRepository $structureRepository     * @return Response     */    public function structuresClient(StructureRepository $structureRepository): Response    {        return $this->render('koh_clients/structures.html.twig', [            'structures' => $structureRepository->findAll()        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/clients/structure/{id}", name="super_admin.structures_show")     * @param Structure $structure     * @param BienClientRepository $bienClientRepository     * @param ExpertiseRepository $expertiseRepository     * @return Response     * @throws NoResultException     * @throws NonUniqueResultException     */    public function showStructure(Structure $structure, BienClientRepository $bienClientRepository, ExpertiseRepository $expertiseRepository): ?Response    {        return $this->render('koh_clients/show_structure.html.twig', [            'structure' => $structure,            'nbBien' => $bienClientRepository->countStructureBiens($structure->getId()),            'nbExpertise' => $expertiseRepository->countStructureExpertises($structure->getId())        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/client/structure/edit/{id}", name="super_admin.structure.edit")     * @param Structure $structure     * @param Request $request     * @return Response     * @throws Exception     */    public function editStructure(Structure $structure, Request $request): Response    {        $form = $this->createForm(StructureType::class, $structure);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $structure->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'La structure a été modifiée');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Modification structure client')                ->setUserAffected($structure->getName());            $entityManager->persist($sysOp);            $entityManager->flush();            return $this->redirectToRoute('super_admin.structures');        }        return $this->render('koh_clients/edit_structure.html.twig', [            'form' => $form->createView()        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/clients/structure/{id}/delete", name="super_admin.structures_delete", methods={"DELETE"})     * @param Structure $structure     * @param Request $request     * @return RedirectResponse     * @throws Exception     */    public function deleteStructureClient(Structure $structure, Request $request): ?RedirectResponse    {        if ($this->isCsrfTokenValid('delete' . $structure->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $users = $structure->getKohUtilisateurs();            foreach ($users as $u) {                if ($u->getIsAdmin()) {                    foreach ($u->getBienClients() as $bienClient) {                        $entityManager->remove($bienClient);                        $entityManager->flush();                    }                }                $entityManager->remove($u);                $entityManager->flush();            }            $entityManager->remove($structure);            $entityManager->flush();            $this->addFlash('success', 'La structure ainsi que ces utilisateurs ont été supprimé');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Suppression compte client')                ->setUserAffected($structure->getName());            $entityManager->persist($sysOp);            $entityManager->flush();        }        return $this->redirectToRoute('super_admin.structures');    }    /**     * @Route("/koh/client/client_by_type", name="koh_client.client_by_type", methods={"POST"})     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @param Request $request     * @return JsonResponse     */    public function loadKohClientParticulier(KohUtilisateurRepository $kohUtilisateurRepository, Request $request): JsonResponse    {        $array_client = array();        $clients = $kohUtilisateurRepository->koh_clients();        foreach ($clients as $client) {            if ($client->getTypeCompte()->getIsStructure() && strcmp(strtolower($request->get('type')), 'structure') === 0) {                $c = array(                    'id' => $client->getId(),                    'email' => $client->getStructure()->getName(),                );                $array_client[] = $c;            }            if (!$client->getTypeCompte()->getIsStructure() && strcmp(strtolower($request->get('type')), 'particulier') === 0) {                $c = array(                    'id' => $client->getId(),                    'email' => $client->getEmail()                );                $array_client[] = $c;            }        }        return new JsonResponse($array_client, 200);    }    /**     * Edition du compte client par admin     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/clients/{id}/edit", name="super_admin.clients.edit", methods={"GET", "POST"})     * @param KohUtilisateur $kohUtilisateur     * @param Request $request     * @param UserPasswordEncoderInterface $encoder     * @return Response     * @throws Exception     */    public function edit(KohUtilisateur $kohUtilisateur, Request $request, UserPasswordEncoderInterface $encoder): Response    {        $form = $this->createForm(EditKohClientType::class, $kohUtilisateur);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $kohUtilisateur->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));            $kohUtilisateur->setPassword($encoder->encodePassword($kohUtilisateur, $kohUtilisateur->getPassword()));            $entityManager->flush();            $this->addFlash('success', 'Le compte a été modifié');            return $this->redirectToRoute('super_admin.clients');        }        return $this->render('koh_clients/edit.html.twig', [            'form' => $form->createView(),            'kohUtilisateur' => $kohUtilisateur        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/clients/activation-account/{id}", name="super_admin.clients.active_account")     * @param KohUtilisateur $kohUtilisateur     * @return RedirectResponse     * @throws Exception     */    public function activeClient(KohUtilisateur $kohUtilisateur): RedirectResponse    {        $kohUtilisateur->setIsActived(true);        $kohUtilisateur->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));        $kohUtilisateur->setStatus('complete');        $entityManager = $this->getDoctrine()->getManager();        $entityManager->flush();        $this->addFlash('success', 'Le compte a été activé avec succes');        return $this->redirectToRoute('super_admin.clients');    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/clients/desactivation-account/{id}", name="super_admin.clients.desactive_account")     * @param KohUtilisateur $kohUtilisateur     * @return RedirectResponse     * @throws Exception     */    public function desactiveClient(KohUtilisateur $kohUtilisateur): RedirectResponse    {        $kohUtilisateur->setIsActived(false);        $kohUtilisateur->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));        $kohUtilisateur->setStatus('compte suspendu');        $entityManager = $this->getDoctrine()->getManager();        $entityManager->flush();        $this->addFlash('success', 'Le compte a été desactivé avec succes');        return $this->redirectToRoute('super_admin.clients');    }    /**     * @Security("is_granted('ROLE_ADMIN') and user.getIsActived() and not user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/admin/utilisateurs/profile-utilisateur/{id}", name="admin.utilisateur.profile")     * @param KohUtilisateur $kohUtilisateur     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @return Response     */    public function userProfile(KohUtilisateur $kohUtilisateur, KohUtilisateurRepository $kohUtilisateurRepository): Response    {        if ($this->getUser()->getId() !== $kohUtilisateur->getId()) {            $kohUtilisateur = $kohUtilisateurRepository->find($this->getUser()->getId());        }        if ($kohUtilisateur->getTypeCompte()->getIsStructure()) {            return $this->render('koh_clients/user_structure_profile.html.twig', [                'koh_utilisateur' => $kohUtilisateur            ]);        }        return $this->render('koh_clients/user_particulier_profile.html.twig', [            'koh_utilisateur' => $kohUtilisateur        ]);    }    /**     * @Security("user.getIsActived() and not user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/admin/utilisateurs/change-user-profile", name="admin.utilisateurs.change_user_profile", methods={"POST"})     * @param Request $request     * @param KohUtilisateurRepository $utilisateurRepository     * @return RedirectResponse     * @throws Exception     */    public function changeUserProfile(Request $request, KohUtilisateurRepository $utilisateurRepository): ?RedirectResponse    {        $user = $utilisateurRepository->findOneBy(['username' => $this->getUser()->getUsername()]);        $mimes = "image/gif, image/png, image/jpeg";        // dd($request->files->get('profile_user'));        // if (str_contains($mimes, $request->files->get('profile_user')['type'])) {            // TODO REPLACE CODE        if (str_contains($mimes, $request->files->get('profile_user')->getMimeType())) {            // TODO REPLACE CODE            $file = $request->files->get('profile_user');            // $fileF = new UploadedFile(                // $request->files->get('profile_user')['tmp_name'],                // $request->files->get('profile_user')['name']);            // $user->setUserProfile($request->files->get('profile_user'));            // $user->setUserProfile($fileF);            $user->setUserProfile($file);            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Le profile a été changé avec success');            return $this->redirectToRoute('admin.utilisateur.profile', ['id' => $user->getId()]);        }        $this->addFlash('danger', 'Le type de fichier choisi n\'est pas accepté');        return $this->redirectToRoute('admin.utilisateur.profile', ['id' => $user->getId()]);    }    /**     * @param int $strength     * @return string     */    public function generate_string(int $strength = 16): string    {        $permitted_chars = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';        $input_length = strlen($permitted_chars);        $random_string = '';        for ($i = 0; $i < $strength; $i++) {            try {                $random_character = $permitted_chars[random_int(0, $input_length - 1)];                $random_string .= $random_character;            } catch (Exception $e) {            }        }        return $random_string;    }    /**     * @Route("/koh_utilisateur/clients_by_type", methods={"POST"})     * @param Request $request     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @param TypeCompteRepository $typeCompteRepository     * @return JsonResponse     */    public function kohClientsByType(Request $request, KohUtilisateurRepository $kohUtilisateurRepository, TypeCompteRepository $typeCompteRepository): JsonResponse    {        $type = $typeCompteRepository->find($request->get('type'));        $utilisateurs = $kohUtilisateurRepository->koh_clients();        $array_client = array();        foreach ($utilisateurs as $kohUtilisateur) {            if (strcmp(strtolower($kohUtilisateur->getTypeCompte()->getName()), strtolower($type->getName())) === 0) {                if ($type->getIsStructure()) {                    $u = array(                        'id' => $kohUtilisateur->getId(),                        'email' => $kohUtilisateur->getStructure()->getName(),                        'type' => 'structure'                    );                } else {                    $u = array(                        'id' => $kohUtilisateur->getId(),                        'email' => $kohUtilisateur->getEmail(),                    );                }                $array_client[] = $u;            }        }        return new JsonResponse($array_client, 200);    }}